        const soql = `SELECT Id, Name, Username, Email, UserType, IsActive, Profile.Name, UserRole.Name, LocaleSidKey, TimeZoneSidKey, LanguageLocaleKey, LastLoginDate, CreatedDate FROM User WHERE Id = '${safeUserId}'`;
